func TestBeadCreateRejectsDependsOnParentAncestor(t *testing.T) {
	workingDir := t.TempDir()
	factory := newBeadTestRoot(t, workingDir)
	rootCmd := factory.NewRootCommand()

	rootOut, err := executeCommand(rootCmd, "bead", "create", "Root", "--type", "task")
	require.NoError(t, err)
	rootID := strings.TrimSpace(rootOut)
	require.NotEmpty(t, rootID)

	parentOut, err := executeCommand(rootCmd, "bead", "create", "Parent", "--type", "task", "--parent", rootID)
	require.NoError(t, err)
	parentID := strings.TrimSpace(parentOut)
	require.NotEmpty(t, parentID)

	t.Run("direct-parent", func(t *testing.T) {
		_, err := executeCommand(rootCmd, "bead", "create", "Child direct", "--type", "task", "--parent", parentID, "--depends-on", parentID)
		require.Error(t, err)
		assert.Contains(t, err.Error(), "ancestor in the parent chain")
		assert.Contains(t, err.Error(), parentID)
		assert.Contains(t, err.Error(), parentID+" -> "+rootID)
	})

	t.Run("grandparent-ancestor", func(t *testing.T) {
		_, err := executeCommand(rootCmd, "bead", "create", "Child ancestor", "--type", "task", "--parent", parentID, "--depends-on", rootID)
		require.Error(t, err)
		assert.Contains(t, err.Error(), "ancestor in the parent chain")
		assert.Contains(t, err.Error(), rootID)
		assert.Contains(t, err.Error(), parentID+" -> "+rootID)
	})
}

// DepAdd adds a dependency: id depends on depID.
func (s *Store) DepAdd(id, depID string) error {
	return s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}
		byID := make(map[string]*Bead, len(beads))
		var target *Bead
		depExists := false
		for i := range beads {
			e := &beads[i]
			byID[e.ID] = e
			if e.ID == id {
				target = e
			}
			if e.ID == depID {
				depExists = true
			}
		}
		if target == nil {
			return fmt.Errorf("bead: not found: %s", id)
		}
		if !depExists {
			return fmt.Errorf("bead: dependency not found: %s", depID)
		}
		if id == depID {
			return fmt.Errorf("bead: cannot depend on self")
		}
		if target.HasDep(depID) {
			return nil // already exists
		}
		parentChain, err := beadParentChain(byID, target.Parent)
		if err != nil {
			return err
		}
		if err := rejectAncestorDependency(id, depID, parentChain); err != nil {
			return err
		}

		// Check for circular dependency
		depMap := make(map[string][]string)
		for _, b := range beads {
			depMap[b.ID] = b.DepIDs()
		}
		depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
		if hasCycle(depMap, id) {
			return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
		}

		target.AddDep(depID, "blocks")
		target.UpdatedAt = time.Now().UTC()
		return s.WriteAll(beads)
	})
}

